option.value:
:root {
  --bg: #070910;
  --bg-soft: #0f1527;
  --text: #f5f8ff;
  --muted: #b5bfd4;
  --primary: #71a6ff;
  --primary-strong: #4a8fff;
  --pointer-x: 50%;
  --pointer-y: 50%;
  --glass: rgba(255, 255, 255, 0.08);
  --glass-border: rgba(255, 255, 255, 0.16);
  --radius-lg: 24px;
  --radius-md: 18px;
  --shadow: 0 12px 40px rgba(2, 6, 23, 0.45);
  --shadow-soft: 0 8px 24px rgba(2, 10, 28, 0.28);
  --max-width: 1140px;
}

* {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  margin: 0;
  min-height: 100vh;
  font-family: Inter, Arial, sans-serif;
  color: var(--text);
  background: radial-gradient(circle at top, #121d36 0%, var(--bg) 45%);
  line-height: 1.6;
  overflow-x: hidden;
}

.skip-link {
  position: absolute;
  left: 1rem;
  top: -3rem;
  z-index: 999;
  padding: 0.6rem 0.9rem;
  border-radius: 10px;
  background: #dce9ff;
  color: #07122e;
  font-weight: 700;
  transition: top 0.2s ease;
}

.skip-link:focus-visible {
  top: 1rem;
}

a {
  color: inherit;
  text-decoration: none;
}

.shell {
  width: min(var(--max-width), calc(100% - 2.5rem));
  margin: 0 auto;
}

.site-header {
  position: sticky;
  top: 0;
  z-index: 20;
  padding-top: 0.9rem;
}

.site-header.is-scrolled .nav {
  box-shadow: var(--shadow);
}

.nav {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0.8rem 1rem;
  border-radius: var(--radius-md);
  border: 1px solid var(--glass-border);
  background: rgba(14, 20, 35, 0.8);
  backdrop-filter: blur(14px);
  -webkit-backdrop-filter: blur(14px);
  transition: box-shadow 0.25s ease;
}

.brand {
  display: inline-flex;
  align-items: center;
  gap: 0.65rem;
  font-weight: 700;
  transition: transform 0.25s ease;
}

.brand img {
  width: 38px;
  height: 38px;
  border-radius: 11px;
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.brand:hover img {
  transform: rotate(-4deg) scale(1.06);
  box-shadow: 0 10px 22px rgba(113, 166, 255, 0.28);
}

.nav-content {
  display: flex;
  align-items: center;
  gap: 0.4rem;
}

.nav-content a {
  position: relative;
  padding: 0.5rem 0.8rem;
  border-radius: 999px;
  color: var(--muted);
  transition: all 0.25s ease;
}

.nav-content a::after {
  content: "";
  position: absolute;
  left: 0.8rem;
  right: 0.8rem;
  bottom: 0.33rem;
  height: 1px;
  border-radius: 999px;
  background: rgba(160, 203, 255, 0.9);
  transform: scaleX(0);
  transform-origin: center;
  transition: transform 0.2s ease;
}

.nav-content a:hover,
.nav-content a:focus-visible {
  color: var(--text);
  background: rgba(255, 255, 255, 0.08);
  outline: none;
}

.nav-content a:hover::after,
.nav-content a:focus-visible::after {
  transform: scaleX(1);
}

.nav-toggle {
  display: none;
  width: 42px;
  height: 42px;
  border: 1px solid var(--glass-border);
  border-radius: 12px;
  color: var(--text);
  background: rgba(255, 255, 255, 0.06);
  cursor: pointer;
}

a:focus-visible,
button:focus-visible {
  outline: 2px solid #9cc4ff;
  outline-offset: 3px;
}

.hero {
  position: relative;
  padding: 6rem 0 2rem;
}

.eyebrow {
  margin: 0;
  font-size: 0.86rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.13em;
  color: #96c1ff;
}

h1,
h2,
h3,
p {
  margin: 0;
}

h1 {
  margin-top: 0.75rem;
  font-size: clamp(2rem, 4.8vw, 4rem);
  line-height: 1.1;
}

h1 span {
  color: #bfd8ff;
}

.hero-text {
  margin-top: 1.25rem;
  max-width: 760px;
  color: var(--muted);
  font-size: clamp(1rem, 1.45vw, 1.2rem);
  text-wrap: pretty;
}

.hero-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 0.9rem;
  margin-top: 1.8rem;
}

.btn {
  position: relative;
  overflow: hidden;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.72rem 1.2rem;
  border-radius: 999px;
  font-weight: 600;
  transition: transform 0.25s ease, box-shadow 0.25s ease, background 0.25s ease;
}

.btn::before {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(
    120deg,
    transparent 20%,
    rgba(255, 255, 255, 0.35) 48%,
    transparent 78%
  );
  transform: translateX(-130%);
  transition: transform 0.7s ease;
}

.btn:hover {
  transform: translateY(-2px);
}

.btn:hover::before {
  transform: translateX(130%);
}

.btn-primary {
  color: #01163a;
  background: linear-gradient(120deg, #9ac1ff, #6fa6ff 55%, #8ed5ff);
  box-shadow: 0 10px 30px rgba(113, 166, 255, 0.32);
}

.btn-glass {
  border: 1px solid var(--glass-border);
  background: rgba(255, 255, 255, 0.06);
}

.section {
  padding: 3rem 0;
}

.section-heading {
  margin-bottom: 1.1rem;
}

.section-heading h2 {
  margin-top: 0.45rem;
  font-size: clamp(1.45rem, 3.2vw, 2.25rem);
}

.glass-card {
  position: relative;
  overflow: hidden;
  border: 1px solid var(--glass-border);
  border-radius: var(--radius-lg);
  background: linear-gradient(
	130deg,
	rgba(255, 255, 255, 0.12),
	rgba(255, 255, 255, 0.04)
  );
  backdrop-filter: blur(18px);
  -webkit-backdrop-filter: blur(18px);
  box-shadow: var(--shadow);
  transition: border-color 0.3s ease, box-shadow 0.3s ease;
}

.glass-card::after {
  content: "";
  position: absolute;
  inset: -30%;
  background: radial-gradient(
    360px circle at var(--pointer-x, 50%) var(--pointer-y, 50%),
    rgba(151, 194, 255, 0.22),
    rgba(151, 194, 255, 0)
  );
  opacity: 0;
  transition: opacity 0.25s ease;
  pointer-events: none;
}

.glass-card:hover,
.glass-card.is-hovered {
  border-color: rgba(151, 194, 255, 0.46);
  box-shadow: 0 16px 46px rgba(8, 20, 42, 0.5), var(--shadow-soft);
}

.glass-card:hover::after,
.glass-card.is-hovered::after {
  opacity: 1;
}

.prose {
  padding: 1.4rem;
}

.prose p {
  color: var(--muted);
}

.prose p + p {
  margin-top: 1rem;
}

.stats-grid {
  margin-top: 1.8rem;
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 0.9rem;
}

.stat-card {
  padding: 1rem;
}

.stat-card strong {
  display: block;
  font-size: 1.3rem;
}

.stat-card span {
  color: var(--muted);
  font-size: 0.95rem;
}

.project-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 1rem;
}

.project-card {
  overflow: hidden;
  transition: transform 0.35s ease, border-color 0.35s ease;
}

.project-card:hover {
  transform: translateY(-6px);
  border-color: rgba(151, 194, 255, 0.55);
}

.project-card img {
  width: 100%;
  height: 200px;
  object-fit: cover;
  display: block;
  transition: transform 0.5s ease, filter 0.5s ease;
}

.project-card:hover img {
  transform: scale(1.035);
  filter: saturate(1.06) contrast(1.04);
}

.project-card div {
  padding: 1rem;
}

.project-card h3 {
  margin-bottom: 0.35rem;
  font-size: 1.15rem;
}

.project-card p {
  color: var(--muted);
  min-height: 3.5rem;
}

.project-card a {
  display: inline-flex;
  margin-top: 0.8rem;
  color: #97c2ff;
  font-weight: 600;
  border-radius: 8px;
}

.project-card a::after {
  content: "\2192";
  margin-left: 0.4rem;
  transition: transform 0.2s ease;
}

.project-card:hover a::after {
  transform: translateX(3px);
}


.skills-wrap {
  padding: 1rem;
  display: flex;
  flex-wrap: wrap;
  gap: 0.7rem;
}

.skills-wrap span {
  padding: 0.55rem 0.8rem;
  border: 1px solid rgba(255, 255, 255, 0.15);
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.06);
  color: #d6e5ff;
  transition: transform 0.25s ease, background 0.25s ease, border-color 0.25s ease;
}

.skills-wrap span:hover {
  transform: translateY(-2px);
  border-color: rgba(151, 194, 255, 0.55);
  background: rgba(151, 194, 255, 0.16);
}

.contact-panel {
  padding: 1.2rem;
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 0.75rem;
}

.contact-panel a {
  display: flex;
  align-items: center;
  gap: 0.55rem;
  color: #d7e7ff;
  padding: 0.75rem 0.85rem;
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.05);
  transition: background 0.2s ease, transform 0.2s ease;
}

.contact-panel a:hover {
  background: rgba(255, 255, 255, 0.11);
  transform: translateY(-2px);
}

.contact-panel a:focus-visible,
.project-card a:focus-visible,
.btn:focus-visible {
  box-shadow: 0 0 0 4px rgba(151, 194, 255, 0.25);
}

.site-footer {
  padding: 2.5rem 0 2rem;
  color: #8f9bb2;
  text-align: center;
}

.background-orb {
  position: fixed;
  pointer-events: none;
  z-index: -1;
  width: 380px;
  height: 380px;
  border-radius: 50%;
  filter: blur(90px);
  opacity: 0.34;
  animation: orbFloat 12s ease-in-out infinite;
}

.orb-a {
  top: -120px;
  left: -120px;
  background: #5f8fff;
}

.orb-b {
  top: 25%;
  right: -90px;
  background: #58d3ff;
  animation-delay: -4s;
}

.orb-c {
  bottom: -140px;
  left: 35%;
  background: #8d68ff;
  animation-delay: -7s;
}

.reveal {
  opacity: 0;
  transform: translateY(24px);
  transition: transform 0.7s ease, opacity 0.7s ease;
}

.reveal.in-view {
  opacity: 1;
  transform: translateY(0);
}

.hero-project {
  padding: 6rem 0 2.5rem;
}

.project-layout {
  display: grid;
  grid-template-columns: 1fr;
  gap: 1rem;
}

.video-card {
  padding: 0.8rem;
}

.video-card iframe {
  width: 100%;
  min-height: 280px;
  border: 0;
  border-radius: 16px;
}

.project-points {
  padding: 1.1rem;
}

.project-points ul {
  margin: 0.6rem 0 0;
  padding-left: 1.2rem;
  color: var(--muted);
}

.project-points li + li {
  margin-top: 0.45rem;
}

@keyframes orbFloat {
  0%,
  100% {
	transform: translateY(0) scale(1);
  }
  50% {
	transform: translateY(-24px) scale(1.04);
  }
}

@media (max-width: 900px) {
  .stats-grid,
  .project-grid,
  .contact-panel {
	grid-template-columns: 1fr;
  }

  .nav-toggle {
	display: inline-flex;
	align-items: center;
	justify-content: center;
  }

  .nav-content {
	position: absolute;
	left: 1.25rem;
	right: 1.25rem;
	top: calc(100% + 0.5rem);
	border-radius: 16px;
	border: 1px solid var(--glass-border);
	background: rgba(14, 20, 35, 0.92);
	backdrop-filter: blur(18px);
	display: none;
	flex-direction: column;
	align-items: stretch;
	gap: 0;
	overflow: hidden;
  }

  .nav-content a {
	border-radius: 0;
	padding: 0.85rem 1rem;
  }

  .nav-content.is-open {
	display: flex;
  }
}

@media (min-width: 901px) {
  .project-layout {
	grid-template-columns: 1.35fr 1fr;
  }
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
	animation: none !important;
	transition: none !important;
	scroll-behavior: auto !important;
  }

  .reveal {
	opacity: 1;
	transform: none;
  }
}

