  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 0.9rem;
}

.stat-card {
  padding: 1rem;
}

.stat-card strong {
  display: block;
  font-size: 1.3rem;
}

.stat-card span {
  color: var(--muted);
  font-size: 0.95rem;
}

.projects-intro {
  margin-top: 0.65rem;
  max-width: 760px;
  color: #c7d3ea;
  text-wrap: pretty;
}

.projects-showcase {
  display: grid;
  grid-template-columns: 1.2fr 1fr;
  gap: 1rem;
}

.project-featured-card {
  display: grid;
  grid-template-columns: 1fr;
}

.project-featured-media-wrap {
  position: relative;
}

.project-featured-media-wrap img {
  width: 100%;
  height: 260px;
  object-fit: cover;
  display: block;
}

.project-badge {
  position: absolute;
  top: 0.85rem;
  right: 0.85rem;
  padding: 0.32rem 0.62rem;
  border-radius: 999px;
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: #081938;
  background: linear-gradient(125deg, #9fc5ff, #8de3ff);
}

.project-featured-content {
  padding: 1.05rem;
}

.project-kicker {
  margin-bottom: 0.35rem;
  font-size: 0.78rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: #a9cbff;
}

.project-featured-content h3,
.project-card-modern h3 {
  margin-bottom: 0.45rem;
  font-size: 1.2rem;
}

.project-featured-content p,
.project-card-modern p {
  color: var(--muted);
}

.project-tags {
  margin-top: 0.9rem;
  display: flex;
  flex-wrap: wrap;
  gap: 0.45rem;
}

.project-tags span {
  padding: 0.24rem 0.56rem;
  border-radius: 999px;
  font-size: 0.78rem;
  color: #d6e6ff;
  border: 1px solid rgba(255, 255, 255, 0.18);
  background: rgba(255, 255, 255, 0.06);
}

.project-grid-modern {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 1rem;
}

.project-card-modern {
  overflow: hidden;
  transition: transform 0.35s ease, border-color 0.35s ease;
}

.project-card-modern:hover,
.project-featured-card:hover {
  transform: translateY(-6px);
  border-color: rgba(151, 194, 255, 0.55);
}

.project-card-modern img {
  width: 100%;
  height: 165px;
  object-fit: cover;
  display: block;
  transition: transform 0.5s ease, filter 0.5s ease;
}

.project-card-modern:hover img,
.project-featured-card:hover .project-featured-media-wrap img {
  transform: scale(1.035);
  filter: saturate(1.06) contrast(1.04);
}

.project-card-modern div {
  padding: 1rem;
}

.project-cta {
  display: inline-flex;
  margin-top: 0.8rem;
  color: #97c2ff;
  font-weight: 600;
  border-radius: 8px;
}

.project-cta::after {
  content: "\2192";
  margin-left: 0.4rem;
  transition: transform 0.2s ease;
}

.project-card-modern:hover .project-cta::after,
.project-featured-card:hover .project-cta::after {
  transform: translateX(3px);
}


.skills-wrap {
  padding: 1rem;
  display: flex;
  flex-wrap: wrap;
  gap: 0.7rem;
}

.skills-wrap span {
  padding: 0.55rem 0.8rem;
  border: 1px solid rgba(255, 255, 255, 0.15);
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.06);
  color: #d6e5ff;
  transition: transform 0.25s ease, background 0.25s ease, border-color 0.25s ease;
}

.skills-wrap span:hover {
  transform: translateY(-2px);
  border-color: rgba(151, 194, 255, 0.55);
  background: rgba(151, 194, 255, 0.16);
}

.contact-panel {
  padding: 1.2rem;
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 0.75rem;
}

.contact-panel a {
  display: flex;
  align-items: center;
  gap: 0.55rem;
  color: #d7e7ff;
  padding: 0.75rem 0.85rem;
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.05);
  transition: background 0.2s ease, transform 0.2s ease;
}

.contact-panel a:hover {
  background: rgba(255, 255, 255, 0.11);
  transform: translateY(-2px);
}

.contact-panel a:focus-visible,
.project-cta:focus-visible,
.btn:focus-visible {
  box-shadow: 0 0 0 4px rgba(151, 194, 255, 0.25);
}

.site-footer {
  padding: 2.5rem 0 2rem;
  color: #8f9bb2;
  text-align: center;
}

.background-orb {
  position: fixed;
  pointer-events: none;
  z-index: -1;
  width: 380px;
  height: 380px;
  border-radius: 50%;
  filter: blur(90px);
  opacity: 0.34;
  animation: orbFloat 12s ease-in-out infinite;
}

.orb-a {
  top: -120px;
  left: -120px;
  background: #5f8fff;
}

.orb-b {
  top: 25%;
  right: -90px;
  background: #58d3ff;
  animation-delay: -4s;
}

.orb-c {
  bottom: -140px;
  left: 35%;
  background: #8d68ff;
  animation-delay: -7s;
}

.reveal {
  opacity: 0;
  transform: translateY(24px);
  transition: transform 0.7s ease, opacity 0.7s ease;
}

.reveal.in-view {
  opacity: 1;
  transform: translateY(0);
}

.hero-project {
  padding: 6rem 0 2.5rem;
}

.project-layout {
  display: grid;
  grid-template-columns: 1fr;
  gap: 1rem;
}

.video-card {
  padding: 0.8rem;
}

.video-card iframe {
  width: 100%;
  min-height: 280px;
  border: 0;
  border-radius: 16px;
}

.project-points {
  padding: 1.1rem;
}

.project-points ul {
  margin: 0.6rem 0 0;
  padding-left: 1.2rem;
  color: var(--muted);
}

.project-points li + li {
  margin-top: 0.45rem;
}

@keyframes orbFloat {
  0%,
  100% {
	transform: translateY(0) scale(1);
  }
  50% {
	transform: translateY(-24px) scale(1.04);
  }
}

@media (max-width: 900px) {
  .stats-grid,
  .project-grid-modern,
  .contact-panel {
	grid-template-columns: 1fr;
  }

  .projects-showcase {
	grid-template-columns: 1fr;
  }

  .nav-toggle {
	display: inline-flex;
	align-items: center;
	justify-content: center;
  }

  .nav-content {
	position: absolute;
	left: 1.25rem;
	right: 1.25rem;
	top: calc(100% + 0.5rem);
	border-radius: 16px;
	border: 1px solid var(--glass-border);
	background: rgba(14, 20, 35, 0.92);
	backdrop-filter: blur(18px);
	display: none;
	flex-direction: column;
	align-items: stretch;
	gap: 0;
	overflow: hidden;
  }

  .nav-content a {
	border-radius: 0;
	padding: 0.85rem 1rem;
  }

  .nav-content.is-open {
	display: flex;
  }
}

@media (min-width: 901px) {
  .project-layout {
	grid-template-columns: 1.35fr 1fr;
  }
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
	animation: none !important;
	transition: none !important;
	scroll-behavior: auto !important;
  }

  .reveal {
	opacity: 1;
	transform: none;
  }
}
